insert into pir_questions
  (question, host_answer, accepted_answer, numeric_target, unit, category, background, reference_1, reference_2, fact_type, source_url)
values
  ('How much did one biblical talent weigh?', 'About 75 pounds (34 kilograms).', '70–80 lb', 75, 'lb', 'Money & Value', 'A talent was primarily a large unit of weight used for metals, not a single coin. A common classroom conversion is 3,000 shekels or about 34 kg.', 'Exodus 38:24–26', '2 Samuel 12:30', 'Historical conversion', 'https://www.reuters.com/world/india/gold-track-biggest-weekly-loss-six-iran-war-fans-inflation-worries-2026-07-17/; https://www.julianspriggs.co.uk/pages/TalentConverter; https://www.biblegateway.com/resources/encyclopedia-of-the-bible/Weights-Measures'),
  ('Using the workbook''s gold price, what is one talent of gold worth in raw metal?', 'Calculated from the editable Inputs sheet.', 'Within 5% of Formula Result', null, 'USD', 'Money & Value', 'This is raw modern metal value, not ancient purchasing power. The workbook assumes a 34 kg talent.', 'Exodus 25:39', '1 Kings 9:28', 'Modern-value estimate', 'https://www.reuters.com/world/india/gold-track-biggest-weekly-loss-six-iran-war-fans-inflation-worries-2026-07-17/; https://www.julianspriggs.co.uk/pages/TalentConverter; https://www.biblegateway.com/resources/encyclopedia-of-the-bible/Weights-Measures'),
  ('Using the workbook''s silver price, what is one talent of silver worth in raw metal?', 'Calculated from the editable Inputs sheet.', 'Within 5% of Formula Result', null, 'USD', 'Money & Value', 'This is raw modern metal value. Silver was much less valuable than gold but was frequently used for payment and tribute.', '2 Kings 5:5', 'Matthew 18:24', 'Modern-value estimate', 'https://www.reuters.com/world/india/gold-track-biggest-weekly-loss-six-iran-war-fans-inflation-worries-2026-07-17/; https://www.julianspriggs.co.uk/pages/TalentConverter; https://www.biblegateway.com/resources/encyclopedia-of-the-bible/Weights-Measures'),
  ('Using the workbook''s gold price, what is one gold shekel worth in raw metal?', 'Calculated from the editable Inputs sheet.', 'Within 5% of Formula Result', null, 'USD', 'Money & Value', 'A shekel began as a unit of weight. The workbook derives its weight from one talent divided by 3,000 shekels.', 'Joshua 7:21', '2 Samuel 24:24', 'Modern-value estimate', 'https://www.reuters.com/world/india/gold-track-biggest-weekly-loss-six-iran-war-fans-inflation-worries-2026-07-17/; https://www.julianspriggs.co.uk/pages/TalentConverter; https://www.biblegateway.com/resources/encyclopedia-of-the-bible/Weights-Measures'),
  ('Using the workbook''s silver price, what is one silver shekel worth in raw metal?', 'Calculated from the editable Inputs sheet.', 'Within 5% of Formula Result', null, 'USD', 'Money & Value', 'The exact weight of a shekel varied, so the workbook uses a consistent classroom assumption.', 'Genesis 23:16', 'Exodus 30:13', 'Modern-value estimate', 'https://www.reuters.com/world/india/gold-track-biggest-weekly-loss-six-iran-war-fans-inflation-worries-2026-07-17/; https://www.julianspriggs.co.uk/pages/TalentConverter; https://www.biblegateway.com/resources/encyclopedia-of-the-bible/Weights-Measures'),
  ('If Judas''s 30 pieces of silver were 30 silver shekels, what is their raw silver value today?', 'Calculated from the editable Inputs sheet.', 'Within 5% of Formula Result', null, 'USD', 'Money & Value', 'The identification of the pieces as shekels is a common reconstruction, not stated directly in Matthew. The biblical meaning is greater than the raw metal price.', 'Zechariah 11:12–13', 'Matthew 26:14–16', 'Modern-value estimate', 'https://www.reuters.com/world/india/gold-track-biggest-weekly-loss-six-iran-war-fans-inflation-worries-2026-07-17/; https://www.julianspriggs.co.uk/pages/TalentConverter; https://www.biblegateway.com/resources/encyclopedia-of-the-bible/Weights-Measures'),
  ('How many talents of gold did Solomon receive in one year?', '666 talents.', 'Exact: 666', 666, 'talents', 'Money & Value', 'The text presents this annual gold income as part of Solomon''s extraordinary wealth.', '1 Kings 10:14', '2 Chronicles 9:13', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=1%20Kings%2010%3A14%3B%202%20Chronicles%209%3A13&version=ESV'),
  ('How many talents of gold did the Queen of Sheba give Solomon?', '120 talents.', 'Exact: 120', 120, 'talents', 'Money & Value', 'The Queen of Sheba also brought spices and precious stones.', '1 Kings 10:10', '2 Chronicles 9:9', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=1%20Kings%2010%3A10%3B%202%20Chronicles%209%3A9&version=ESV'),
  ('How many talents of gold did Solomon''s fleet bring from Ophir in 1 Kings?', '420 talents.', 'Exact: 420; note 450 in 2 Chronicles', 420, 'talents', 'Money & Value', 'First Kings reports 420 talents, while 2 Chronicles 8:18 reports 450. Use 420 because the question specifies 1 Kings.', '1 Kings 9:28', '2 Chronicles 8:18', 'Textual parallel difference', 'https://www.biblegateway.com/passage/?search=1%20Kings%209%3A28%3B%202%20Chronicles%208%3A18&version=ESV'),
  ('How many talents of gold did David personally dedicate for the Temple?', '3,000 talents.', 'Exact: 3,000', 3000, 'talents', 'Money & Value', 'David said this gift came from his personal treasure in addition to what he had already prepared.', '1 Chronicles 29:3–4', '1 Chronicles 29:7', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=1%20Chronicles%2029%3A3%E2%80%934%3B%201%20Chronicles%2029%3A7&version=ESV'),
  ('How many talents of silver did David personally dedicate for the Temple?', '7,000 talents.', 'Exact: 7,000', 7000, 'talents', 'Money & Value', 'The gift was intended for overlaying the walls of the Temple structures.', '1 Chronicles 29:3–4', '1 Chronicles 29:7', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=1%20Chronicles%2029%3A3%E2%80%934%3B%201%20Chronicles%2029%3A7&version=ESV'),
  ('How many talents of silver did Haman offer the king?', '10,000 talents.', 'Exact: 10,000', 10000, 'talents', 'Money & Value', 'Haman offered the enormous payment in connection with his plan to destroy the Jewish people.', 'Esther 3:8–9', 'Esther 4:7', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Esther%203%3A8%E2%80%939%3B%20Esther%204%3A7&version=ESV'),
  ('How many talents of gold did Assyria demand from Hezekiah?', '30 talents.', 'Exact: 30', 30, 'talents', 'Money & Value', 'Hezekiah stripped gold from the Temple doors and doorposts to help pay the demand.', '2 Kings 18:14–16', 'Isaiah 36:1', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=2%20Kings%2018%3A14%E2%80%9316%3B%20Isaiah%2036%3A1&version=ESV'),
  ('How many talents of silver did Assyria demand from Hezekiah?', '300 talents.', 'Exact: 300', 300, 'talents', 'Money & Value', 'The silver demand was ten times the number of gold talents demanded.', '2 Kings 18:14', '2 Chronicles 32:1', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=2%20Kings%2018%3A14%3B%202%20Chronicles%2032%3A1&version=ESV'),
  ('How many shekels made one mina in Ezekiel''s standard?', '60 shekels.', 'Exact: 60', 60, 'shekels', 'Money & Value', 'Ancient systems varied, but Ezekiel explicitly defines a mina as 60 shekels in this passage.', 'Ezekiel 45:12', 'Ezra 2:69', 'Biblical unit definition', 'https://www.biblegateway.com/resources/encyclopedia-of-the-bible/Weights-Measures'),
  ('About how much labor did one denarius normally represent in Jesus''s parables?', 'About one day''s wage.', 'Exact concept: 1 day', 1, 'day''s wage', 'Money & Value', 'Workers in the vineyard agreed to work for one denarius for the day.', 'Matthew 20:1–2', 'Revelation 6:6', 'Historical economic context', 'https://www.biblegateway.com/passage/?search=Matthew%2020%3A1%E2%80%932%3B%20Revelation%206%3A6&version=ESV'),
  ('How many days'' wages was the perfume poured on Jesus estimated to be worth?', 'More than 300 days'' wages.', '300–365 days', 300, 'denarii', 'Money & Value', 'The perfume was valued at more than 300 denarii, nearly a laborer''s annual income.', 'Mark 14:3–5', 'John 12:3–5', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Mark%2014%3A3%E2%80%935%3B%20John%2012%3A3%E2%80%935&version=ESV'),
  ('How many days'' wages did the disciples say would not buy enough bread for the 5,000?', '200 days'' wages.', 'Exact: 200', 200, 'denarii', 'Money & Value', 'Even 200 denarii would only give each person a small amount.', 'Mark 6:37', 'John 6:7', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Mark%206%3A37%3B%20John%206%3A7&version=ESV'),
  ('The widow''s two small coins together equaled what fraction of a denarius?', 'About 1/64 of a denarius.', 'Accept 1/64 or about 1.6%', 0.015625, 'denarius', 'Money & Value', 'Two lepta equaled one quadrans, one of the smallest Roman monetary amounts.', 'Mark 12:41–44', 'Luke 21:1–4', 'Historical coin conversion', 'https://www.biblegateway.com/passage/?search=Mark%2012%3A41%E2%80%9344%3B%20Luke%2021%3A1%E2%80%934&version=ESV'),
  ('About how many years of daily wages was the unforgiving servant''s 10,000-talent debt?', 'About 164,000 years.', '150,000–170,000 years', 164384, 'years', 'Money & Value', 'Using the common New Testament conversion of 6,000 denarii per talent, the debt equals 60 million daily wages. Jesus used an intentionally impossible debt.', 'Matthew 18:23–28', 'Matthew 18:32–35', 'Calculated biblical illustration', 'https://www.biblegateway.com/passage/?search=Matthew%2018%3A23%E2%80%9328%3B%20Matthew%2018%3A32%E2%80%9335&version=ESV'),
  ('How long was Noah''s ark?', '300 cubits, about 450 feet.', '440–460 ft', 450, 'ft', 'Measurements & Construction', 'The ark was about one and a half American football fields long.', 'Genesis 6:14–16', 'Genesis 7:17–18', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Genesis%206%3A14%E2%80%9316%3B%20Genesis%207%3A17%E2%80%9318&version=ESV'),
  ('How wide was Noah''s ark?', '50 cubits, about 75 feet.', '70–80 ft', 75, 'ft', 'Measurements & Construction', 'Its length was six times its width.', 'Genesis 6:15', 'Genesis 7:18', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Genesis%206%3A15%3B%20Genesis%207%3A18&version=ESV'),
  ('How high was Noah''s ark?', '30 cubits, about 45 feet.', '40–50 ft', 45, 'ft', 'Measurements & Construction', 'The ark contained lower, second and third decks.', 'Genesis 6:15–16', 'Genesis 7:23', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Genesis%206%3A15%E2%80%9316%3B%20Genesis%207%3A23&version=ESV'),
  ('How long was King Og''s iron bed?', 'Nine cubits, about 13.5 feet.', '13–14 ft', 13.5, 'ft', 'Measurements & Construction', 'The bed was also four cubits, about six feet, wide and was remembered as evidence of Og''s unusual size.', 'Deuteronomy 3:11', 'Numbers 21:33–35', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Deuteronomy%203%3A11%3B%20Numbers%2021%3A33%E2%80%9335&version=ESV'),
  ('How tall was Goliath in the traditional Hebrew reading?', 'Six cubits and a span, about 9 feet 9 inches.', '9.5–10 ft; also accept 6 ft 9 in with manuscript explanation', 9.75, 'ft', 'Measurements & Construction', 'Some ancient manuscripts read four cubits and a span, about 6 feet 9 inches. The traditional Masoretic reading is taller.', '1 Samuel 17:4', '1 Samuel 17:23', 'Textual manuscript difference', 'https://www.biblegateway.com/passage/?search=1%20Samuel%2017%3A4%3B%201%20Samuel%2017%3A23&version=ESV'),
  ('How much did Goliath''s iron spearhead weigh?', '600 shekels, about 15 pounds.', '14–16 lb', 15, 'lb', 'Measurements & Construction', 'This is only the iron spearhead, not the heavy wooden shaft.', '1 Samuel 17:7', '2 Samuel 21:19', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=1%20Samuel%2017%3A7%3B%202%20Samuel%2021%3A19&version=ESV'),
  ('How long was Solomon''s Temple building?', '60 cubits, about 90 feet.', '85–95 ft', 90, 'ft', 'Measurements & Construction', 'This describes the main Temple structure, not the entire Temple complex.', '1 Kings 6:2', '2 Chronicles 3:3', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=1%20Kings%206%3A2%3B%202%20Chronicles%203%3A3&version=ESV'),
  ('How wide was Solomon''s Temple building?', '20 cubits, about 30 feet.', '28–32 ft', 30, 'ft', 'Measurements & Construction', 'The building was three times longer than it was wide.', '1 Kings 6:2', '2 Chronicles 3:3', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=1%20Kings%206%3A2%3B%202%20Chronicles%203%3A3&version=ESV'),
  ('How high was Solomon''s Temple building?', '30 cubits, about 45 feet.', '40–50 ft', 45, 'ft', 'Measurements & Construction', 'The interior was lined with cedar and overlaid with gold.', '1 Kings 6:2', '1 Kings 6:20–22', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=1%20Kings%206%3A2%3B%201%20Kings%206%3A20%E2%80%9322&version=ESV'),
  ('What were the dimensions of Solomon''s Most Holy Place?', '20 cubits long, wide and high: a 30-foot cube.', '20 cubits each direction', 20, 'cubits per side', 'Measurements & Construction', 'The ark of the covenant was placed in this cubic inner room.', '1 Kings 6:20', '2 Chronicles 3:8', 'Exact biblical measurement', 'https://www.biblegateway.com/passage/?search=1%20Kings%206%3A20%3B%202%20Chronicles%203%3A8&version=ESV'),
  ('What was the diameter of the bronze Sea at Solomon''s Temple?', '10 cubits, about 15 feet.', '14–16 ft', 15, 'ft', 'Measurements & Construction', 'The huge basin stood on twelve bronze oxen.', '1 Kings 7:23–25', '2 Chronicles 4:2–4', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=1%20Kings%207%3A23%E2%80%9325%3B%202%20Chronicles%204%3A2%E2%80%934&version=ESV'),
  ('How much water did Solomon''s bronze Sea hold?', '2,000 baths in 1 Kings; 3,000 baths in 2 Chronicles.', 'Accept either with the correct reference', 2500, 'baths', 'Measurements & Construction', 'The passages may describe normal capacity and maximum capacity, although Scripture does not explain the difference.', '1 Kings 7:26', '2 Chronicles 4:5', 'Textual parallel difference', 'https://www.biblegateway.com/passage/?search=1%20Kings%207%3A26%3B%202%20Chronicles%204%3A5&version=ESV'),
  ('How large was the Tabernacle courtyard?', '100 by 50 cubits, about 150 by 75 feet.', '100 × 50 cubits', 11250, 'sq ft', 'Measurements & Construction', 'The portable sanctuary stood inside this curtained rectangular courtyard.', 'Exodus 27:9–18', 'Exodus 38:9–20', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Exodus%2027%3A9%E2%80%9318%3B%20Exodus%2038%3A9%E2%80%9320&version=ESV'),
  ('How large was the bronze altar at the Tabernacle?', 'Five cubits square and three cubits high: about 7.5 × 7.5 × 4.5 feet.', '5 × 5 × 3 cubits', 7.5, 'ft wide', 'Measurements & Construction', 'The altar was built of acacia wood covered with bronze.', 'Exodus 27:1–8', 'Exodus 38:1–7', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Exodus%2027%3A1%E2%80%938%3B%20Exodus%2038%3A1%E2%80%937&version=ESV'),
  ('How long was each main curtain covering the Tabernacle?', '28 cubits, about 42 feet.', '40–44 ft', 42, 'ft', 'Measurements & Construction', 'Each curtain was four cubits, about six feet, wide.', 'Exodus 26:1–2', 'Exodus 36:8–9', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Exodus%2026%3A1%E2%80%932%3B%20Exodus%2036%3A8%E2%80%939&version=ESV'),
  ('How tall was Nebuchadnezzar''s gold image?', '60 cubits, about 90 feet.', '85–95 ft', 90, 'ft', 'Measurements & Construction', 'It was only six cubits wide, giving it extremely tall proportions.', 'Daniel 3:1', 'Daniel 3:4–6', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Daniel%203%3A1%3B%20Daniel%203%3A4%E2%80%936&version=ESV'),
  ('How tall was the pole or gallows Haman prepared for Mordecai?', '50 cubits, about 75 feet.', '70–80 ft', 75, 'ft', 'Measurements & Construction', 'Haman was ultimately executed on the structure he prepared for Mordecai.', 'Esther 5:14', 'Esther 7:9–10', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Esther%205%3A14%3B%20Esther%207%3A9%E2%80%9310&version=ESV'),
  ('How long was each side of the New Jerusalem in Revelation?', '12,000 stadia, roughly 1,400 miles.', '1,350–1,500 miles', 1400, 'miles', 'Measurements & Construction', 'The city is described as equally long, wide and high.', 'Revelation 21:15–16', 'Revelation 21:2', 'Converted apocalyptic measurement', 'https://www.biblegateway.com/passage/?search=Revelation%2021%3A15%E2%80%9316%3B%20Revelation%2021%3A2&version=ESV'),
  ('How high was the New Jerusalem''s wall?', '144 cubits, about 216 feet.', '205–225 ft', 216, 'ft', 'Measurements & Construction', 'This measurement describes the wall; the city itself is described on a far greater scale.', 'Revelation 21:17', 'Revelation 21:12–14', 'Converted apocalyptic measurement', 'https://www.biblegateway.com/passage/?search=Revelation%2021%3A17%3B%20Revelation%2021%3A12%E2%80%9314&version=ESV'),
  ('How far above the mountains did the floodwaters rise?', '15 cubits, about 22.5 feet.', '20–25 ft', 22.5, 'ft', 'Measurements & Construction', 'Genesis emphasizes that the mountains were completely covered.', 'Genesis 7:19–20', 'Genesis 8:3–5', 'Converted biblical measurement', 'https://www.biblegateway.com/passage/?search=Genesis%207%3A19%E2%80%9320%3B%20Genesis%208%3A3%E2%80%935&version=ESV'),
  ('About how many Israelite men left Egypt on foot?', 'About 600,000 men, besides women and children.', '580,000–620,000', 600000, 'men', 'Armies, Crowds & Censuses', 'The total traveling population would have been considerably larger because the count excludes women and children.', 'Exodus 12:37–38', 'Numbers 11:21', 'Rounded biblical number', 'https://www.biblegateway.com/passage/?search=Exodus%2012%3A37%E2%80%9338%3B%20Numbers%2011%3A21&version=ESV'),
  ('How many fighting-age Israelite men were counted in the first wilderness census?', '603,550.', 'Exact: 603,550', 603550, 'men', 'Armies, Crowds & Censuses', 'The tribe of Levi was counted separately.', 'Numbers 1:45–47', 'Exodus 38:26', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Numbers%201%3A45%E2%80%9347%3B%20Exodus%2038%3A26&version=ESV'),
  ('How many fighting-age Israelite men were counted in the second wilderness census?', '601,730.', 'Exact: 601,730', 601730, 'men', 'Armies, Crowds & Censuses', 'This census occurred near the end of the wilderness period before Israel entered Canaan.', 'Numbers 26:1–4', 'Numbers 26:51', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Numbers%2026%3A1%E2%80%934%3B%20Numbers%2026%3A51&version=ESV'),
  ('How many male Levites one month old or older were counted?', '22,000.', 'Exact: 22,000', 22000, 'males', 'Armies, Crowds & Censuses', 'The Levites were counted separately because they were assigned responsibility for the Tabernacle.', 'Numbers 3:14–16', 'Numbers 3:39', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Numbers%203%3A14%E2%80%9316%3B%20Numbers%203%3A39&version=ESV'),
  ('How many firstborn Israelite males were counted in the wilderness?', '22,273.', 'Exact: 22,273', 22273, 'males', 'Armies, Crowds & Censuses', 'Because this exceeded the number of Levites by 273, redemption money was collected for the difference.', 'Numbers 3:40–43', 'Numbers 3:46–51', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Numbers%203%3A40%E2%80%9343%3B%20Numbers%203%3A46%E2%80%9351&version=ESV'),
  ('How many soldiers did Gideon originally have before anyone went home?', '32,000.', 'Exact: 32,000', 32000, 'soldiers', 'Armies, Crowds & Censuses', 'Twenty-two thousand fearful men left, leaving 10,000 before the final reduction.', 'Judges 7:2–3', 'Judges 7:6–7', 'Derived biblical number', 'https://www.biblegateway.com/passage/?search=Judges%207%3A2%E2%80%933%3B%20Judges%207%3A6%E2%80%937&version=ESV'),
  ('How many men remained in Gideon''s final army?', '300.', 'Exact: 300', 300, 'soldiers', 'Armies, Crowds & Censuses', 'God deliberately reduced the army so Israel could not claim victory by its own strength.', 'Judges 7:6–7', 'Judges 7:19–22', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=Judges%207%3A6%E2%80%937%3B%20Judges%207%3A19%E2%80%9322&version=ESV'),
  ('About how large was the Midianite fighting force Gideon faced?', 'About 135,000 sword-bearing men.', '130,000–140,000', 135000, 'soldiers', 'Armies, Crowds & Censuses', 'Judges says 120,000 had fallen and 15,000 remained, allowing the original force to be calculated.', 'Judges 8:10', 'Judges 8:4', 'Derived biblical number', 'https://www.biblegateway.com/passage/?search=Judges%208%3A10%3B%20Judges%208%3A4&version=ESV'),
  ('How large was Jehoshaphat''s listed army when the divisions are added together?', '1,160,000 men.', 'Exact total: 1,160,000', 1160000, 'soldiers', 'Armies, Crowds & Censuses', 'Second Chronicles lists five commanders with forces of 300,000, 280,000, 200,000, 200,000 and 180,000.', '2 Chronicles 17:14–18', '2 Chronicles 17:12–13', 'Derived biblical number', 'https://www.biblegateway.com/passage/?search=2%20Chronicles%2017%3A14%E2%80%9318%3B%202%20Chronicles%2017%3A12%E2%80%9313&version=ESV'),
  ('How many soldiers were in King Asa''s army?', '580,000.', 'Exact: 580,000', 580000, 'soldiers', 'Armies, Crowds & Censuses', 'The force included 300,000 from Judah and 280,000 from Benjamin.', '2 Chronicles 14:8', '2 Chronicles 14:11', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=2%20Chronicles%2014%3A8%3B%202%20Chronicles%2014%3A11&version=ESV'),
  ('How large was Zerah the Cushite''s army?', '1,000,000 men and 300 chariots.', 'Exact: 1,000,000', 1000000, 'soldiers', 'Armies, Crowds & Censuses', 'Asa prayed that God could help the powerless against the mighty army.', '2 Chronicles 14:9–11', '2 Chronicles 14:12–13', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=2%20Chronicles%2014%3A9%E2%80%9311%3B%202%20Chronicles%2014%3A12%E2%80%9313&version=ESV'),
  ('How many chosen warriors did Abijah bring against Jeroboam?', '400,000.', 'Exact: 400,000', 400000, 'soldiers', 'Armies, Crowds & Censuses', 'Both armies are described as chosen, mighty warriors.', '2 Chronicles 13:3', '2 Chronicles 13:12', 'Exact biblical number', 'https://www.biblegateway.com/passage/?search=2%20Chronicles%2013%3A3%3B%202%20Chronicles%2013%3A12&version=ESV'),
